parameters.jsCode:
const result = $input.first().json;

// Build a clean HTML email body from the Markdown output
const md = result.final_markdown || '';
const cost = (result.cost_usd * 100).toFixed(4);
const delta = result.readability?.flesch_ease_delta?.toFixed(1) || 'n/a';
const modes = result.readability?.profile || 'unknown';

const hasDiagram = !!result.mermaid_diagram;
const hasChart   = !!(result.chart_data?.data_points?.length);

return [{
  json: {
    session_id:     result.session_id,
    markdown:       md,
    mermaid:        result.mermaid_diagram || null,
    chart_data:     result.chart_data || null,
    summary: {
      modes,
      cost_cents:       cost,
      readability_gain: delta,
      has_diagram:      hasDiagram,
      has_chart:        hasChart,
      duration_seconds: result.duration_seconds,
    },
    email_subject: `NeuroAlign: your adapted document is ready`,
    email_html: `
<h2>Your NeuroAlign document is ready</h2>
<p><strong>Support modes:</strong> ${modes}</p>
<p><strong>Readability improvement:</strong> +${delta} Flesch points</p>
<p><strong>Processing cost:</strong> $${result.cost_usd.toFixed(5)}</p>
<hr/>
<div style="font-family:Arial,sans-serif;line-height:1.6;max-width:680px">
  <pre style="white-space:pre-wrap;font-family:inherit">${md}</pre>
</div>
${hasDiagram ? '<p><em>A visual diagram was generated. Open the NeuroAlign app to view it rendered.</em></p>' : ''}
    `.trim()
  }
}];

const result = $input.first().json;
return [{
  json: {
    error: result.error || 'Unknown error',
    session_id: result.session_id || 'unknown',
    timestamp: new Date().toISOString()
  }
}];
